VALUES
  ('heelevel3-7c4986e7-moex-00265', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於 X1 年初移轉一建築物之控制將其以$400,000 出售，當時該建築物之帳面金額為 $300,000，公允價值為$500,000，甲公司同時即簽訂5年期租約租回該建築物。租約約定自X1 年底起每年底支付租金$30,000，甲公司確定租賃隱含利率為 5%。甲公司對此售後租回交易 應認列之建築物移轉利益為（答案四捨五入至元）：', '["$51,954", "$64,942", "$91,954", "$108,046"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00266', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '承上題，甲公司對此售後租回交易於 X1 年初應認列之使用權資產帳面金額為（答案四捨五 入至元）：', '["$97,413", "$129,884", "$137,931", "$229,884"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00267', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '下列有關債務工具投資減損之敘述，何者正確？①企業於判定金融工具是否為信用風險低時，', '["企業若判定金融工具於報導日之信用風險低，得假設該金融工具 自原始認列後信用風險並未顯著增加，而以 12 個月預期信用損失來衡量備抵損失", "若某 項金融工具於前一報導期間被視為信用風險低，但於報導日未被視為信用風險低，此時必須 認列該金融工具之存續期間預期信用損失", "衡量預期信用損失時不須考量該債務工具之擔 保品及其他信用增強之影響", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00268', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '企業以權益交割之股份基礎給付換取商品或勞務時，應以所收取商品或勞務之公允價值入帳，但 若該交易之對象為員工時，應以權益工具於下列何一日期之公允價值衡量自員工所取得勞務？', '["服務日", "給與日", "既得日", "執行日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00269', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司實施確定福利退休金計畫，X1年初確定福利義務現值為$800,000，計畫資產公允價值 為$500,000。X1 年當期服務成本為$120,000，精算損失$50,000，折現率 8%，計畫資產實際 報酬$60,000。X1年底，甲公司因修改退休金計畫而產生前期服務成本$80,000。甲公司X1年 應認列退休金費用為多少？', '["$204,000", "$224,000", "$264,000", "$274,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00270', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '認列於財務報表之要素係以貨幣形式量化，因此需要選擇衡量基礎。如果資產負債表中某項 負債依規定應採用現時成本衡量，則該負債應就下列何者衡量？', '["約當負債於衡量日將收取之對價", "約當負債於衡量日將收取之對價加上於該日將發生之交易成本", "約當負債於衡量日將收取之對價減去於該日將發生之交易成本", "預期隨個體履行負債有義務移轉之現金或其他經濟資源之現值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00271', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '下列有關財務報導觀念架構之敘述，何者正確？①適用認列條件及衡量觀念時所用之科目單', '["審慎性和中立描述相違背，所以觀念架構未將審慎性納入", "當企業收購另一 家公司之某產業部門時，該產業部門可能構成一報導個體", "折現值係衡量基礎的一種", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00272', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', 'X1年初甲公司銷貨予丙公司，產生一應收分期帳款，丙公司除頭期款$40,000外，X1年至X4 年每年底需支付$40,000，有效利率相當於10%。X1年底，甲公司X1年對該應收款認列之預 期信用減損損失共計$14,677。X2年底丙公司發生信用減損僅支付$34,000，甲公司估計X3與 X4年度分別僅可收取$32,000及$32,000，試問甲公司X2年對該應收款應認列於本期淨利之 預期信用減損損失金額為？（答案四捨五入至元）', '["($1,404)", "$5,207", "$22,000", "$36,667"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00273', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於20X0年度創立，員工每年有20天之帶薪休假，未休完之剩餘休假天數得以遞延使 用3年。每年休假時將優先使用當年度之休假天數，不足時再依序扣抵前1年度所遞延之剩 餘休假天數，未休完之剩餘休假將不會有現金補償。於20X0年12 月31日，甲公司有100 名員工，平均尚未休完之剩餘年假為7天。甲公司之管理階層預期此7天休假中，20X1年至 20X3年員工將依序使用3天、2天及1天之遞延休假，並放棄1天之遞延休假。此外，甲公 司預期2名員工將於20X1年離職（預估每位離職員工於20X1年度會使用23天休假），其餘 年度無人離職。下列敘述何者正確？', '["甲公司於20X0年12月31日應認列594天之其他長期員工福利負債，並全數分類為流動 負債", "甲公司於20X0年12月31日應認列594天之其他長期員工福利負債，並全數分類為非流 動負債", "甲公司於20X0年12月31日應認列594天之其他長期員工福利負債，並依預期使用年度是否 在一年內，分類為流動負債（預期使用在一年內）及非流動負債（預期使用在一年以上）", "甲公司於20X0年12月31日應認列600天之其他長期員工福利負債，其中300天分類為 流動負債，其餘300天分類為非流動負債 32470"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00274', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X4年7月1日將原始成本$400,000（交換當日資產公允價值為$140,000）之設備作 價$150,000與乙公司公允價值$160,000之設備進行交換，並支付現金$10,000。甲公司換出之 設備係於X2年1月1日購入，估計耐用年限5年，殘值為$25,000，採雙倍數餘額遞減法提 列折舊。另甲公司對換入之設備採年數合計法計提折舊，估計耐用年限4年，殘值為$25,000。 如上述交易應為不具商業實質，而甲公司誤判為具商業實質入帳，試分析上述事件將造成甲 公司X4年度損益高（低）估多少？', '["高估$19,840", "高估$22,800", "高估$24,800", "高估$34,800"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL)
